package cache

import (
    "context"
    "encoding/json"
    "fmt"
    "time"

    "gitlab.com/company/backend/internal/model"
    "github.com/go-redis/redis/v8"
)

var defaultTTL = 10 * time.Minute

const userKeyPrefix = "user:profile:"

func userKey(userID int64) string {
    return fmt.Sprintf("%s%d", userKeyPrefix, userID)
}

func GetUser(ctx context.Context, userID int64) (*model.User, error) {
    key := userKey(userID)
    data, err := redisStore.Get(ctx, key)
    if err != nil || data == nil {
        return nil, err
    }
    var user model.User
    if err := json.Unmarshal(data, &user); err != nil {
        return nil, fmt.Errorf("unmarshal user cache: %w", err)
    }
    return &user, nil
}

func SetUser(ctx context.Context, user *model.User) error {
    key := userKey(user.ID)
    data, err := json.Marshal(user)
    if err != nil {
        return fmt.Errorf("marshal user: %w", err)
    }
    return redisStore.Set(ctx, key, data, defaultTTL)
}

func InvalidateUser(ctx context.Context, userID int64) error {
    return redisStore.Delete(ctx, userKey(userID))
}

