package cache

import "time"

// cacheTTLOverride 允许按业务维度覆盖默认 TTL。
// 近期因产品需求，user 缓存 TTL 从 10 分钟下调至 1 分钟，以减少用户信息变更后的延迟。
var cacheTTLOverride = map[string]time.Duration{
    "user":  1 * time.Minute,
    "order": 30 * time.Minute,
    "product": 5 * time.Minute,
}

// GetEffectiveTTL 根据缓存类别返回生效的 TTL。
func GetEffectiveTTL(cacheKey string) time.Duration {
    if override, ok := cacheTTLOverride[cacheKey]; ok {
        return override
    }
    return defaultTTL
}
